VALUES
  ('aboriginal-6f0ba476-moex-00590', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '依據下列項目所適用之會計準則規定，後續衡量可能會使用公允價值資訊者共有幾項？', '["電腦公司的存貨", "建設公司的投資性不動產", "生技公司的專利權", "畜牧公司對子公司的投資 ⑤水泥公司的待出售非流動資產"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00591', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年2月1日以$2,000,000購入1,000張乙公司債券，分類為「透過其他綜合損益按公 允價值衡量之金融資產」，甲公司於X2年7月1日以每張$2,500出售800張乙公司債券，乙公司 債券X1年12月31日及X2年12月31日之公允價值分別為每張$2,100及$2,800。試問甲公司 X2年「透過其他綜合損益按公允價值衡量金融資產未實現評價損益」中，屬於「重分類調整數」 及「當年度發生之未實現評價損益」分別為多少？', '["$0；$460,000", "$(320,000)；$140,000", "$(320,000)；$400,000", "$(400,000)；$460,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00592', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列資訊，何者並非國際財務報導準則要求企業標示財務報表時必須顯著列示的資訊？', '["財務報表中用以表達金額之單位", "表達貨幣", "經理人簽名或蓋章", "報導企業若於財務報表涵蓋期間內更名，新名稱及舊名稱"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00593', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於 X2 年初將一台機器設備以等於公允價值$4,500,000 的價格出售給乙公司，隨後立即與 乙公司簽訂承租該機器之租賃協議。約定自X2年1月1日起承租4年，每年12月31日支付租 金$519,464。該機器設備原始成本為$8,000,000，累計折舊$5,000,000，剩餘耐用年限尚有6年。經評 估該出售交易之條款，甲公司對該機器設備的控制權已移轉給乙公司。甲公司可確定租賃隱含利率 為6%。則X2年初甲公司應認列移轉該資產之利益金額為多少？（年金現值資料：P4,6%=3.46511）', '["$0", "利益$600,000", "利益$900,000", "利益$1,500,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00594', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司X1年12月31日經董事會通過，將於未來一年內處分A部門，並積極從事處分行動，符 合分類為「待出售處分群組」之要件。假設該部門包含之資產與負債，於X1年12月31日重分 類前之帳列會計項目及相關金額如下： 會計項目 相關金額 成本$300,000，X1年12月31日淨變現價值 存貨 $280,000 透過其他綜合損益按公允價值原始投資時公允價值為$1,000,000， 衡量之權益工具投資 X1年12月31日公允價值為$900,000 X1年12月31日帳列成本$3,000,000，累計折舊 不動產、廠房及設備 $2,000,000，該日之公允價值減出售成本為 $800,000 銀行借款 $500,000 上述A部門在甲公司X1年12月31日資產負債表中所表達的待出售處分部門資產帳面金額為何？', '["$800,000", "$1,480,000", "$1,980,000", "$2,080,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00595', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司所有支出均透過銀行支票存款帳戶處理，乙銀行對帳單列示5月1日餘額$25,800、5月份 存入合計$302,000、提取合計$280,300、5月31日餘額$47,500。經查4月份銀行往來調節表上之 在途存款與未兌現支票分別為$3,000 及$6,800。甲公司於乙銀行之支票存款帳列數如下：5 月份 借記合計$312,000、5月份貸記合計$298,600、5月31日餘額$35,400。經核對銀行對帳單之存入 （提取）欄和公司帳上的銀行存款會計項目借（貸）方記錄，發現差異：銀行方面於5月31日代 收票據（含10%利息）$2,000、並扣除手續費$300。5月份在途存款金額為何？', '["$10,000", "$12,000", "$13,000", "$15,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00596', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司X9年12月31日庫存原材料之成本為$130,000，該原材料若直接出售則扣除銷售費用後 售價為$70,000，但若使用該原材料製造製成品，則估計需要再投入加工成本$150,000，完工後製 成品之估計售價為$255,000，估計銷售費用為售價之10%，試問甲公司X9年12月31日該原材 料之備抵跌價金額為何？', '["$0", "$25,000", "$50,500", "$60,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00597', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列各項目，共有幾項會導致平均成本零售價法下之成本率提高？①淨加價減少  ②正常損壞減少', '["進貨運費增加", "員工折扣減少  ⑤淨減價增加  ⑥進貨折扣增加", "共1項", "共2項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00598', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列有關金融工具之敘述，正確的有那些？①預期不會行使之選擇權（因該選擇權為價外），不是', '["甲公司簽訂一遠期合約，於1年後按遠期價格購買乙公司股份，甲公司於合約開始 時，按乙公司股份之現時價格預付，該遠期合約不是衍生工具", "非屬透過損益按公允價值衡量 之金融資產，其原始衡量應加計直接可歸屬於取得該金融資產之交易成本", "金融工具之原始衡 量，應包括預期將於金融工具移轉或處分時所發生之交易成本", "僅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00599', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列應依預期信用損失模式處理減損之項目有那些？①透過損益按公允價值衡量之債務工具', '["透過損益按公允價值衡量之權益工具", "按攤銷後成本衡量之債務工具", "透過其他綜合損 益按公允價值衡量之債務工具  ⑤由客戶合約交易所產生之合約資產", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
